import{_ as i,o as a,c as t,a2 as o}from"./chunks/framework.OWFDNrRT.js";const u=JSON.parse('{"title":"Diplomacy is Not an Option - Technical Game Notes","description":"","frontmatter":{},"headers":[],"relativePath":"reference/DINO-GAME-NOTES.md","filePath":"reference/DINO-GAME-NOTES.md","lastUpdated":1773460793000}'),r={name:"reference/DINO-GAME-NOTES.md"};function n(l,e,s,d,c,p){return a(),t("div",null,[...e[0]||(e[0]=[o(`<h1 id="diplomacy-is-not-an-option-technical-game-notes" tabindex="-1">Diplomacy is Not an Option - Technical Game Notes <a class="header-anchor" href="#diplomacy-is-not-an-option-technical-game-notes" aria-label="Permalink to &quot;Diplomacy is Not an Option - Technical Game Notes&quot;">​</a></h1><p><strong>Last Updated</strong>: 2026-03-09 <strong>Status</strong>: Research complete (initial pass)</p><hr><h2 id="game-overview" tabindex="-1">Game Overview <a class="header-anchor" href="#game-overview" aria-label="Permalink to &quot;Game Overview&quot;">​</a></h2><ul><li><strong>Genre</strong>: Medieval siege defense RTS / city-builder</li><li><strong>Developer</strong>: Door 407 (door407.com)</li><li><strong>Engine</strong>: Unity with full ECS (DOTS) architecture</li><li><strong>Scripting Backend</strong>: Mono (NOT IL2CPP)</li><li><strong>Platform</strong>: Steam (PC / Windows)</li><li><strong>Release</strong>: February 9, 2022 (Early Access), October 4, 2024 (Full Release)</li></ul><hr><h2 id="modding-landscape" tabindex="-1">Modding Landscape <a class="header-anchor" href="#modding-landscape" aria-label="Permalink to &quot;Modding Landscape&quot;">​</a></h2><h3 id="official-support" tabindex="-1">Official Support <a class="header-anchor" href="#official-support" aria-label="Permalink to &quot;Official Support&quot;">​</a></h3><ul><li><strong>Map Editor</strong> (added May 2025) with full Steam Workshop integration <ul><li>Adjustable terrain, enemy horde waves, timing</li><li>Mission objectives (defend/attack, survive/prosper)</li><li>Random or manual landscape options</li><li>Resource difficulty settings</li></ul></li><li><strong>December 2025</strong>: Winter update making Undead faction playable in Map Editor</li><li>No official overhaul/mod SDK</li><li>No official API documentation</li><li>Developer stance: &quot;open to community mods but prioritize core game development&quot;</li></ul><h3 id="community-modding" tabindex="-1">Community Modding <a class="header-anchor" href="#community-modding" aria-label="Permalink to &quot;Community Modding&quot;">​</a></h3><ul><li>Small Nexus Mods community</li><li>BepInEx-based modding via <strong>modified BepInEx 5 with Doorstop pre-loader fork</strong></li><li>Standard BepInEx from GitHub DOES NOT WORK - requires specialized ECS build</li><li>Custom <code>BepInEx/ecs_plugins/</code> install path (differs from standard BepInEx)</li><li>Nexus/Vortex support confirmed (Vortex extension auto-installs BepInEx)</li></ul><h3 id="existing-mods-nexus" tabindex="-1">Existing Mods (Nexus) <a class="header-anchor" href="#existing-mods-nexus" aria-label="Permalink to &quot;Existing Mods (Nexus)&quot;">​</a></h3><ol><li><strong>BepInEx 5 with Unity ECS Support</strong> - Foundation loader</li><li><strong>Resource Fairy</strong> - Configurable resource/storage multipliers (F1 ConfigManager)</li><li><strong>Trainer and Multipliers</strong> - Unit damage/speed/health, building health, population multipliers</li></ol><h3 id="existing-code-repos" tabindex="-1">Existing Code Repos <a class="header-anchor" href="#existing-code-repos" aria-label="Permalink to &quot;Existing Code Repos&quot;">​</a></h3><ul><li><strong>devopsdinosaur/dno-mods</strong> (GitHub) - Primary mod source repo <ul><li>Visual Studio solution (<code>dno-mods.sln</code>)</li><li>Directories: <code>resource_fairy/</code>, <code>shared/</code>, <code>system_test/</code>, <code>testing/</code>, <code>third-party/</code></li><li>100% C#, 29 commits, single contributor</li><li>All built mods published on Nexus</li></ul></li></ul><hr><h2 id="key-technical-details" tabindex="-1">Key Technical Details <a class="header-anchor" href="#key-technical-details" aria-label="Permalink to &quot;Key Technical Details&quot;">​</a></h2><h3 id="ecs-architecture" tabindex="-1">ECS Architecture <a class="header-anchor" href="#ecs-architecture" aria-label="Permalink to &quot;ECS Architecture&quot;">​</a></h3><ul><li>Uses <strong>full Unity ECS</strong> (Entity Component System) via DOTS</li><li><strong>Not hybrid ECS</strong> - full DOTS implementation</li><li>Burst compilation for performance</li><li>Custom <code>ecs_plugins</code> flow for game-specific plugins</li></ul><h3 id="bepinex-setup-critical" tabindex="-1">BepInEx Setup (CRITICAL) <a class="header-anchor" href="#bepinex-setup-critical" aria-label="Permalink to &quot;BepInEx Setup (CRITICAL)&quot;">​</a></h3><ul><li><strong>Standard BepInEx from GitHub does NOT work</strong></li><li>Required: BepInEx 5 with modified Doorstop pre-loader (C++ winhttp.dll)</li><li>Doorstop fork allows multiple assembly pre-loading</li><li>Source: Nexus Mods (diplomacyisnotanoption/mods/1)</li></ul><p><strong>Folder Structure</strong>:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>GameRoot/</span></span>
<span class="line"><span>  winhttp.dll              # Modified Doorstop</span></span>
<span class="line"><span>  doorstop_config.ini</span></span>
<span class="line"><span>  BepInEx/</span></span>
<span class="line"><span>    plugins/               # Standard plugins folder (EMPTY for DINO)</span></span>
<span class="line"><span>    ecs_plugins/            # WHERE DINO MODS GO</span></span>
<span class="line"><span>    config/                 # Configuration files</span></span></code></pre></div><h3 id="modding-path" tabindex="-1">Modding Path <a class="header-anchor" href="#modding-path" aria-label="Permalink to &quot;Modding Path&quot;">​</a></h3><ol><li>Install modified BepInEx/Doorstop for Unity ECS</li><li>Mods go into <code>BepInEx/ecs_plugins/</code>, NOT standard <code>BepInEx/plugins/</code></li><li>ECS-native mods preferred over Harmony patches</li><li>Plugins use attribute-based registration (standard BepInEx pattern)</li></ol><h3 id="harmony-compatibility" tabindex="-1">Harmony Compatibility <a class="header-anchor" href="#harmony-compatibility" aria-label="Permalink to &quot;Harmony Compatibility&quot;">​</a></h3><ul><li>Prefix patches (run before methods): <strong>COMPATIBLE</strong></li><li>Postfix patches (run after methods): <strong>COMPATIBLE</strong></li><li>Transpiler patches: <strong>NOT RECOMMENDED</strong> (ECS architecture limitations)</li><li><strong>Performance Warning</strong>: Steam guide (id:3348001330) warns severe perf cost</li><li>Removing Burst-generated DLL can halve frame rate</li><li>Recommends writing ECS-based mods directly</li></ul><hr><h2 id="key-game-systems" tabindex="-1">Key Game Systems <a class="header-anchor" href="#key-game-systems" aria-label="Permalink to &quot;Key Game Systems&quot;">​</a></h2><h3 id="economy" tabindex="-1">Economy <a class="header-anchor" href="#economy" aria-label="Permalink to &quot;Economy&quot;">​</a></h3><ul><li><strong>5 resource types</strong>: Food, Wood, Stone, Iron, Gold</li><li>Trading system via &quot;merchant dirigible&quot;</li><li>Gold obtained exclusively through trading (high exchange rates)</li><li>Resource production and storage critical to strategy</li><li>Late-game heavily dependent on gold conversion strategy</li></ul><h3 id="military" tabindex="-1">Military <a class="header-anchor" href="#military" aria-label="Permalink to &quot;Military&quot;">​</a></h3><ul><li>Real-time combat with pause mechanics</li><li>Unit positioning and flanking critical</li><li>Diverse unit types (cavalry, infantry, archers, etc.)</li><li>Progressive unit unlock via tech tree</li><li>Unit upgrades through research</li></ul><h3 id="building" tabindex="-1">Building <a class="header-anchor" href="#building" aria-label="Permalink to &quot;Building&quot;">​</a></h3><ul><li>Economic buildings (farms, woodcutters, quarries, mines)</li><li>Military buildings (barracks, stables, towers)</li><li>Production buildings (markets, smithies)</li><li>Research buildings (universities)</li><li>Defense structures (walls, gates)</li></ul><h3 id="technology-upgrades" tabindex="-1">Technology &amp; Upgrades <a class="header-anchor" href="#technology-upgrades" aria-label="Permalink to &quot;Technology &amp; Upgrades&quot;">​</a></h3><ul><li>University reduces research time</li><li>14+ technologies available</li><li>Tech tree system with dependencies</li><li>Unit and building upgrades</li></ul><h3 id="magic-system" tabindex="-1">Magic System <a class="header-anchor" href="#magic-system" aria-label="Permalink to &quot;Magic System&quot;">​</a></h3><ul><li>Magical monuments</li><li>Soul crystal harvesting</li><li>Summoned units/ghosts</li><li>Beam attack spells</li></ul><h3 id="waves-ai" tabindex="-1">Waves &amp; AI <a class="header-anchor" href="#waves-ai" aria-label="Permalink to &quot;Waves &amp; AI&quot;">​</a></h3><ul><li>Procedurally generated maps with enemy spawns</li><li>Wave-based enemy assault system</li><li>Multiple attack directions</li><li>Progressive difficulty scaling</li><li>&quot;Vast hordes&quot; (25,000+ enemies reported)</li></ul><hr><h2 id="vanilla-unit-to-role-mapping-for-mod-conversion" tabindex="-1">Vanilla Unit-to-Role Mapping (for mod conversion) <a class="header-anchor" href="#vanilla-unit-to-role-mapping-for-mod-conversion" aria-label="Permalink to &quot;Vanilla Unit-to-Role Mapping (for mod conversion)&quot;">​</a></h2><p>These vanilla game elements map to abstract modding roles:</p><table tabindex="0"><thead><tr><th>Vanilla Element</th><th>Abstract Role</th></tr></thead><tbody><tr><td>Peasant worker</td><td>Economy worker</td></tr><tr><td>Swordsman</td><td>Line infantry</td></tr><tr><td>Archer / ranged</td><td>Ranged infantry</td></tr><tr><td>Cavalry</td><td>Fast strike unit</td></tr><tr><td>Catapult / trebuchet</td><td>Siege / artillery</td></tr><tr><td>Walls / towers</td><td>Static defense</td></tr><tr><td>Farms</td><td>Economy primary</td></tr><tr><td>Town hall / castle</td><td>Command center</td></tr><tr><td>Magic / soul</td><td>Special ability proxy</td></tr></tbody></table><hr><h2 id="tool-chain" tabindex="-1">Tool Chain <a class="header-anchor" href="#tool-chain" aria-label="Permalink to &quot;Tool Chain&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Tool</th><th>Purpose</th></tr></thead><tbody><tr><td>BepInEx 5 (ECS build)</td><td>Plugin/mod framework (modified for DINO)</td></tr><tr><td>HarmonyX</td><td>Method patching (use sparingly - perf cost)</td></tr><tr><td>AssetRipper</td><td>Unity asset extraction</td></tr><tr><td>dnSpy / ILSpy</td><td>Managed assembly inspection / decompilation</td></tr><tr><td>Unity.Entities</td><td>ECS-native system creation</td></tr><tr><td>Visual Studio</td><td>Mod development (C#)</td></tr><tr><td>ConfigurationManager</td><td>In-game config UI (F1 key)</td></tr><tr><td>Vortex</td><td>Mod manager with DINO extension</td></tr></tbody></table><hr><h2 id="open-questions" tabindex="-1">Open Questions <a class="header-anchor" href="#open-questions" aria-label="Permalink to &quot;Open Questions&quot;">​</a></h2><ul><li>[ ] Exact Unity version used by DINO</li><li>[x] <s>Mono vs IL2CPP runtime</s> -&gt; <strong>Mono confirmed</strong></li><li>[ ] Complete entity/component namespace map (requires decompilation)</li><li>[ ] Prefab organization and naming conventions</li><li>[ ] Asset bundle structure</li><li>[ ] Localization table format</li><li>[ ] Research tree data format</li><li>[ ] Wave composition data format</li><li>[ ] Available hook/patch points in ECS systems</li></ul><hr><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><h3 id="primary" tabindex="-1">Primary <a class="header-anchor" href="#primary" aria-label="Permalink to &quot;Primary&quot;">​</a></h3><ul><li><a href="https://www.nexusmods.com/diplomacyisnotanoption" target="_blank" rel="noreferrer">Nexus Mods - Diplomacy is Not an Option</a> -- Mod downloads and community hub</li><li><a href="https://www.nexusmods.com/diplomacyisnotanoption/mods/1" target="_blank" rel="noreferrer">BepInEx 5 with Unity ECS Support</a> -- Required mod loader (modified Doorstop fork)</li><li><a href="https://steamcommunity.com/sharedfiles/filedetails/?id=3348001330" target="_blank" rel="noreferrer">Steam Community Modding Guide</a> -- &quot;Modding is an Option (with BepInEx)&quot; -- primary BepInEx setup reference</li><li><a href="https://github.com/devopsdinosaur/dno-mods" target="_blank" rel="noreferrer">devopsdinosaur/dno-mods</a> -- Community mod source code (Resource Fairy, Trainer)</li><li><a href="https://steamcommunity.com/app/1272320/workshop/" target="_blank" rel="noreferrer">Steam Workshop</a> -- Official map sharing (Map Editor maps only, not code mods)</li></ul><h3 id="nexus-mods-available" tabindex="-1">Nexus Mods Available <a class="header-anchor" href="#nexus-mods-available" aria-label="Permalink to &quot;Nexus Mods Available&quot;">​</a></h3><ul><li><a href="https://www.nexusmods.com/diplomacyisnotanoption/mods/1" target="_blank" rel="noreferrer">BepInEx 5 with Unity ECS Support</a> -- Foundation loader</li><li><a href="https://www.nexusmods.com/diplomacyisnotanoption/mods/2" target="_blank" rel="noreferrer">Resource Fairy</a> -- Configurable resource/storage multipliers (F1 ConfigManager)</li><li><a href="https://www.nexusmods.com/diplomacyisnotanoption/mods/3" target="_blank" rel="noreferrer">Trainer and Multipliers</a> -- Unit damage/speed/health, building health, population multipliers</li></ul><h3 id="secondary" tabindex="-1">Secondary <a class="header-anchor" href="#secondary" aria-label="Permalink to &quot;Secondary&quot;">​</a></h3><ul><li><a href="https://www.nexusmods.com/site/mods/1070" target="_blank" rel="noreferrer">Vortex Extension for DINO</a> -- Adds DINO support to Vortex Mod Manager (auto-installs BepInEx)</li><li><a href="https://pcgamingwiki.com/wiki/Diplomacy_Is_Not_an_Option" target="_blank" rel="noreferrer">PCGamingWiki</a></li><li><a href="https://diplomacy-is-not-an-option.fandom.com" target="_blank" rel="noreferrer">Fandom Wiki</a></li><li><a href="https://www.moddb.com/games/diplomacy-is-not-an-option/mods" target="_blank" rel="noreferrer">ModDB</a></li><li><a href="https://steamdb.info/app/1272320/patchnotes/" target="_blank" rel="noreferrer">SteamDB Patch Notes</a></li><li><a href="https://door407.com" target="_blank" rel="noreferrer">Door 407 (Developer)</a></li><li><a href="https://store.steampowered.com/app/1272320/Diplomacy_is_Not_an_Option/" target="_blank" rel="noreferrer">Steam Store Page</a></li></ul><h3 id="map-editor-official" tabindex="-1">Map Editor (Official) <a class="header-anchor" href="#map-editor-official" aria-label="Permalink to &quot;Map Editor (Official)&quot;">​</a></h3><p>The May 2025 update added a full Map Editor with Steam Workshop integration:</p><ul><li>Adjustable terrain, enemy horde waves, timing</li><li>Mission objectives (defend/attack, survive/prosper)</li><li>Random or manual landscape options</li><li>Resource difficulty settings</li><li>December 2025 update made Undead faction playable in Map Editor</li><li>Maps only -- the Workshop does not support code mods</li></ul><h3 id="comparable-bepinex-modding-scenes-for-reference" tabindex="-1">Comparable BepInEx Modding Scenes (for reference) <a class="header-anchor" href="#comparable-bepinex-modding-scenes-for-reference" aria-label="Permalink to &quot;Comparable BepInEx Modding Scenes (for reference)&quot;">​</a></h3><ul><li>Valheim (mature BepInEx + Thunderstore ecosystem)</li><li>Risk of Rain 2 (BepInEx reference game)</li><li>The Long Dark (Harmony patching reference)</li><li>RimWorld (modding-friendly architecture reference)</li></ul>`,64)])])}const h=i(r,[["render",n]]);export{u as __pageData,h as default};
